var n="\n/* Default buttons */\n~ button {\n    cursor: pointer;\n}\n~ button.active {\n    background: var(--ok_bg-accent);\n}\n\n~ button:hover {\n    background: color-mix(in srgb, var(--ok_bg) 50%, var(--ok_bg-accent));\n    box-shadow: var(--ok_shadow-strong);\n}\n\n~ button:active {\n    background: color-mix(in srgb, var(--ok_bg) 90%, var(--ok_fg));\n}\n\n~ button:focus {\n    box-shadow: 0 0 0 2px var(--ok_focus-ring);\n    outline: none;\n}\n\n~ button:focus-visible {\n    box-shadow: 0 0 0 2px var(--ok_focus-ring);\n    outline: calc(var(--ok_space-xs)) solid var(--ok_fg-accent);\n}\n\n~ button:disabled {\n    opacity: 0.5;\n    filter: grayscale(0.3);\n    cursor: not-allowed;\n}";export{n as default};
